// ─── JIGSAW PUZZLE ENGINE ─────────────────────────────────────────────────
// Image: Assamese Kheer with orange slices (real photo, base64 inlined).
// 3×3 grid. Click a tile to select it, click another to swap.
// Solve all 9 → stamp awarded.

const GRID = 3;
const TOTAL_TILES = GRID * GRID;
const TILE_SIZE = 100; // px — each tile shows a 100×100 slice of a 300×300 image

const IMAGE_SRC = 'data:image/webp;base64,';

// ─── State ────────────────────────────────────────────────────────────────
let tiles = [];        // tiles[slotIdx] = correctPosition index
let selectedIdx = null;
let jigsawSolved = false;

// ─── DOM ──────────────────────────────────────────────────────────────────
const jigsawBoard   = document.getElementById('jigsawBoard');
const checkJigsaw   = document.getElementById('checkJigsaw');
const shuffleJigsaw = document.getElementById('shuffleJigsaw');
const jigsawResult  = document.getElementById('jigsawResult');

// ─── Preload image then build ─────────────────────────────────────────────
const img = new Image();
img.onload = buildTiles;
img.onerror = () => { jigsawResult.textContent = 'Image failed to load.'; };
img.src = IMAGE_SRC;

function buildTiles() {
  tiles = Array.from({ length: TOTAL_TILES }, (_, i) => i);
  shuffleTiles();
  renderBoard();
}

function shuffleTiles() {
  do {
    for (let i = tiles.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [tiles[i], tiles[j]] = [tiles[j], tiles[i]];
    }
  } while (isSolved());
  selectedIdx = null;
  jigsawSolved = false;
  jigsawResult.textContent = '';
}

function isSolved() {
  return tiles.every((v, i) => v === i);
}

// ─── Render ───────────────────────────────────────────────────────────────
// Each tile is a <canvas> that draws the correct 100×100 slice of the photo.
// The image is 300×300 in display space — if the photo isn't square, we
// center-crop it so the most interesting part (the kheer bowl) is visible.
function renderBoard() {
  jigsawBoard.innerHTML = '';

  tiles.forEach((correctPos, slotIdx) => {
    const col = correctPos % GRID;   // which column this piece belongs to
    const row = Math.floor(correctPos / GRID);

    const btn = document.createElement('button');
    btn.className = 'jigsaw-tile';
    btn.type = 'button';
    btn.setAttribute('aria-label', `Puzzle piece ${slotIdx + 1} of ${TOTAL_TILES}`);
    btn.dataset.slot = slotIdx;

    const canvas = document.createElement('canvas');
    canvas.width  = TILE_SIZE;
    canvas.height = TILE_SIZE;

    const ctx = canvas.getContext('2d');

    // Center-crop: find the largest square we can take from the source image
    const srcSize = Math.min(img.naturalWidth, img.naturalHeight);
    const srcX = Math.round((img.naturalWidth  - srcSize) / 2);
    const srcY = Math.round((img.naturalHeight - srcSize) / 2);

    // Each tile covers 1/3 of that square in each dimension
    const sliceSize = srcSize / GRID;
    ctx.drawImage(
      img,
      srcX + col * sliceSize,  // source x
      srcY + row * sliceSize,  // source y
      sliceSize,               // source width
      sliceSize,               // source height
      0, 0,                    // dest x, y
      TILE_SIZE,               // dest width
      TILE_SIZE                // dest height
    );

    btn.appendChild(canvas);
    btn.addEventListener('click', () => onTileClick(slotIdx));
    jigsawBoard.appendChild(btn);
  });

  updateSelection();
}

function updateSelection() {
  jigsawBoard.querySelectorAll('.jigsaw-tile').forEach((tile, i) => {
    tile.classList.toggle('is-selected',    i === selectedIdx);
    tile.classList.toggle('is-correct-pos', tiles[i] === i);
  });
}

// ─── Interaction ──────────────────────────────────────────────────────────
function onTileClick(slotIdx) {
  if (jigsawSolved) return;

  if (selectedIdx === null) {
    selectedIdx = slotIdx;
    updateSelection();
    return;
  }

  if (selectedIdx === slotIdx) {
    selectedIdx = null;
    updateSelection();
    return;
  }

  // Swap
  [tiles[selectedIdx], tiles[slotIdx]] = [tiles[slotIdx], tiles[selectedIdx]];
  selectedIdx = null;
  renderBoard();

  if (isSolved()) {
    jigsawSolved = true;
    jigsawBoard.classList.add('is-solved');
    jigsawResult.textContent = '🎉 Kheer assembled! Vadapav is very proud.';
    if (typeof earnStamp   === 'function') earnStamp('jigsaw');
    if (typeof showToast   === 'function') showToast('Jigsaw stamp earned! 🍊 Kheer for the whole carnival.');
  }
}

function onCheck() {
  if (jigsawSolved) return;
  const correct = tiles.filter((v, i) => v === i).length;
  jigsawResult.textContent = correct === TOTAL_TILES
    ? '🎉 Kheer assembled! Vadapav is very proud.'
    : `${correct} of ${TOTAL_TILES} tiles in place. Keep going!`;
}

function onShuffle() {
  jigsawBoard.classList.remove('is-solved');
  shuffleTiles();
  renderBoard();
}

checkJigsaw.addEventListener('click', onCheck);
shuffleJigsaw.addEventListener('click', onShuffle);